import React, { useState, useRef } from 'react';
import { Link } from 'react-router-dom';
import { useBook } from '../context/BookContext';
import StarField from '../components/StarField';

/* ── Text style options ── */
const TEXT_STYLES = [
  { value: 'normal',    label: 'Normal',    preview: 'The cosmos within us.' },
  { value: 'elegant',   label: 'Elegant',   preview: 'The cosmos within us.' },
  { value: 'bold',      label: 'Bold',      preview: 'THE COSMOS WITHIN.' },
  { value: 'wide',      label: 'Spaced',    preview: 'The cosmos within.' },
  { value: 'condensed', label: 'Condensed', preview: 'The cosmos within us — a story.' },
];

const STYLE_CSS = {
  normal:    { fontFamily:"'Cormorant Garamond',serif", fontStyle:'normal', fontWeight:300, letterSpacing:'0.01em', fontSize:'14px' },
  elegant:   { fontFamily:"'IM Fell English',serif",   fontStyle:'italic', fontWeight:400, letterSpacing:'0.02em', fontSize:'13.5px' },
  bold:      { fontFamily:"'Cinzel',serif",             fontStyle:'normal', fontWeight:600, letterSpacing:'0.06em', fontSize:'12px' },
  wide:      { fontFamily:"'Cormorant Garamond',serif", fontStyle:'normal', fontWeight:300, letterSpacing:'0.14em', fontSize:'13px' },
  condensed: { fontFamily:"'Cormorant Garamond',serif", fontStyle:'normal', fontWeight:400, letterSpacing:'-0.01em',fontSize:'13.5px', lineHeight:'1.55' },
};

/* ── small sub-components ── */
function Field({ label, children, hint }) {
  return (
    <div className="field">
      <label className="field-label">{label}</label>
      {hint && <span className="field-hint">{hint}</span>}
      {children}
    </div>
  );
}

function Input({ value, onChange, placeholder, type = 'text' }) {
  return <input className="ad-input" type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} />;
}

function Textarea({ value, onChange, placeholder, rows = 8 }) {
  return <textarea className="ad-textarea" value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} rows={rows} />;
}

/* ── PageEditor panel ── */
function PageEditor({ page, onUpdate, onDelete, onMoveUp, onMoveDown, index, total }) {
  const [open, setOpen] = useState(false);
  const fileRef = useRef();

  const handleImage = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) { alert('Image must be under 2 MB'); return; }
    const reader = new FileReader();
    reader.onload = (ev) => onUpdate({ image: ev.target.result });
    reader.readAsDataURL(file);
  };

  return (
    <div className={`page-card ${open ? 'open' : ''}`}>
      <div className="page-card-header" onClick={() => setOpen(o => !o)}>
        <div className="page-card-left">
          <span className="page-card-num">{index + 1}</span>
          <div>
            <p className="page-card-title">{page.title || 'Untitled'}</p>
            <p className="page-card-chapter">{page.chapter}</p>
          </div>
          {page.image && <span className="page-card-badge img">📷</span>}
          <span className={`page-card-badge style`}>{page.textStyle}</span>
        </div>
        <div className="page-card-actions">
          <button className="icon-btn" title="Move up"   onClick={e => { e.stopPropagation(); onMoveUp();   }} disabled={index === 0}>↑</button>
          <button className="icon-btn" title="Move down" onClick={e => { e.stopPropagation(); onMoveDown(); }} disabled={index === total - 1}>↓</button>
          <button className="icon-btn danger" title="Delete" onClick={e => { e.stopPropagation(); if (window.confirm('Delete this page?')) onDelete(); }}>✕</button>
          <span className="chevron">{open ? '▲' : '▼'}</span>
        </div>
      </div>

      {open && (
        <div className="page-card-body">
          {/* Chapter & Title */}
          <div className="field-row">
            <Field label="Chapter Label">
              <Input value={page.chapter} onChange={v => onUpdate({ chapter: v })} placeholder="Chapter I" />
            </Field>
            <Field label="Page Title">
              <Input value={page.title} onChange={v => onUpdate({ title: v })} placeholder="The First Light" />
            </Field>
          </div>

          {/* Content */}
          <Field label="Content" hint="Paragraphs separated by blank lines">
            <Textarea value={page.content} onChange={v => onUpdate({ content: v })} placeholder="Write your page content here..." rows={7} />
          </Field>

          {/* Quote */}
          <Field label="Pull Quote" hint="Optional short quote shown at the bottom">
            <Input value={page.quote} onChange={v => onUpdate({ quote: v })} placeholder="A memorable line from this page..." />
          </Field>

          {/* Text Style */}
          <Field label="Text Style">
            <div className="style-grid">
              {TEXT_STYLES.map(s => (
                <button
                  key={s.value}
                  className={`style-btn ${page.textStyle === s.value ? 'active' : ''}`}
                  onClick={() => onUpdate({ textStyle: s.value })}
                >
                  <span className="style-btn-name">{s.label}</span>
                  <span className="style-preview" style={STYLE_CSS[s.value]}>{s.preview}</span>
                </button>
              ))}
            </div>
          </Field>

          {/* Image */}
          <Field label="Page Image" hint="Optional — max 2 MB, displayed above text">
            <div className="image-zone">
              {page.image ? (
                <div className="image-preview-wrap">
                  <img src={page.image} alt="" className="image-preview" />
                  <div className="image-preview-actions">
                    <button className="ad-btn sm" onClick={() => fileRef.current.click()}>Replace</button>
                    <button className="ad-btn sm danger" onClick={() => onUpdate({ image: null, imageCaption: '' })}>Remove</button>
                  </div>
                </div>
              ) : (
                <button className="upload-btn" onClick={() => fileRef.current.click()}>
                  <span className="upload-icon">🖼</span>
                  <span>Click to upload image</span>
                  <span className="upload-hint">PNG, JPG, WebP · max 2 MB</span>
                </button>
              )}
              <input ref={fileRef} type="file" accept="image/*" hidden onChange={handleImage} />
            </div>
            {page.image && (
              <div style={{ marginTop: 8 }}>
                <Input value={page.imageCaption} onChange={v => onUpdate({ imageCaption: v })} placeholder="Image caption (optional)" />
              </div>
            )}
          </Field>
        </div>
      )}
    </div>
  );
}

/* ── Main AdminPage ── */
export default function AdminPage() {
  const { book, updateBook, addPage, updatePage, deletePage, movePage, resetBook } = useBook();
  const [tab, setTab] = useState('pages'); // 'pages' | 'meta'
  const [saved, setSaved] = useState(false);

  const handleSave = () => {
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <div className="admin-root">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;600;700&family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=IM+Fell+English:ital@0;1&family=JetBrains+Mono:wght@400&display=swap');

        .admin-root {
          min-height:100vh;
          background:var(--admin-bg);
          color:var(--text-base);
          font-family:'Cormorant Garamond',serif;
          position:relative;
          overflow-x:hidden;
        }

        /* ── top bar ── */
        .admin-bar {
          position:sticky; top:0; z-index:100;
          background:rgba(10,10,18,.92);
          backdrop-filter:blur(12px);
          border-bottom:1px solid var(--admin-border);
          display:flex; align-items:center; justify-content:space-between;
          padding:0 28px; height:58px;
          gap:16px;
        }
        .admin-bar-left { display:flex; align-items:center; gap:16px; }
        .admin-logo {
          font-family:'Cinzel',serif; font-size:13px;
          letter-spacing:.3em; color:rgba(240,192,64,.6);
          text-transform:uppercase; white-space:nowrap;
        }
        .admin-bar-sep { width:1px; height:24px; background:var(--admin-border); }
        .back-link {
          font-family:'JetBrains Mono',monospace; font-size:11px;
          color:var(--text-muted); text-decoration:none; letter-spacing:.1em;
          display:flex; align-items:center; gap:6px; transition:color .2s;
        }
        .back-link:hover { color:var(--text-base); }

        .admin-bar-right { display:flex; align-items:center; gap:10px; }
        .save-badge {
          font-family:'Cinzel',serif; font-size:10px; letter-spacing:.2em;
          color:var(--success); padding:4px 12px;
          border:1px solid rgba(46,204,113,.3); border-radius:4px;
          animation:fadeIn .2s;
        }
        @keyframes fadeIn { from{opacity:0;transform:translateY(-4px)} to{opacity:1;transform:none} }

        /* ── layout ── */
        .admin-layout {
          max-width:900px; margin:0 auto;
          padding:32px 24px 80px;
          display:flex; flex-direction:column; gap:28px;
        }

        /* ── tabs ── */
        .tab-bar {
          display:flex; gap:4px;
          background:rgba(255,255,255,.03);
          border:1px solid var(--admin-border);
          border-radius:var(--radius); padding:4px;
          width:fit-content;
        }
        .tab-btn {
          font-family:'Cinzel',serif; font-size:11px; letter-spacing:.2em;
          text-transform:uppercase; padding:8px 20px;
          border:none; background:transparent; color:var(--text-muted);
          border-radius:6px; transition:all .2s; cursor:pointer;
        }
        .tab-btn.active {
          background:var(--admin-accent-dim); color:var(--admin-accent);
          box-shadow:0 0 12px rgba(108,99,255,.15);
        }
        .tab-btn:hover:not(.active) { background:rgba(255,255,255,.04); color:var(--text-dim); }

        /* ── section card ── */
        .section-card {
          background:var(--admin-surface);
          border:1px solid var(--admin-border);
          border-radius:var(--radius-lg); overflow:hidden;
        }
        .section-head {
          padding:18px 24px;
          border-bottom:1px solid var(--admin-border);
          display:flex; align-items:center; justify-content:space-between;
        }
        .section-title {
          font-family:'Cinzel',serif; font-size:13px; letter-spacing:.2em;
          color:rgba(240,192,64,.7); text-transform:uppercase;
        }
        .section-body { padding:24px; display:flex; flex-direction:column; gap:18px; }

        /* ── fields ── */
        .field { display:flex; flex-direction:column; gap:6px; }
        .field-label {
          font-family:'Cinzel',serif; font-size:10px; letter-spacing:.25em;
          color:var(--text-muted); text-transform:uppercase;
        }
        .field-hint { font-size:11px; color:rgba(255,255,255,.25); margin-top:-2px; font-style:italic; }
        .field-row { display:grid; grid-template-columns:1fr 1fr; gap:16px; }
        @media(max-width:560px){ .field-row{ grid-template-columns:1fr; } }

        .ad-input, .ad-textarea, .ad-select {
          background:rgba(255,255,255,.04);
          border:1px solid rgba(255,255,255,.1);
          border-radius:var(--radius); color:var(--text-base);
          padding:10px 14px; font-size:14px;
          font-family:'Cormorant Garamond',serif;
          transition:border-color .2s, box-shadow .2s;
          width:100%; resize:none;
        }
        .ad-input:focus, .ad-textarea:focus, .ad-select:focus {
          outline:none;
          border-color:rgba(108,99,255,.5);
          box-shadow:0 0 0 3px rgba(108,99,255,.08);
          background:rgba(255,255,255,.05);
        }
        .ad-select { appearance:none; cursor:pointer; }

        /* ── style grid ── */
        .style-grid { display:grid; grid-template-columns:repeat(auto-fill,minmax(150px,1fr)); gap:10px; }
        .style-btn {
          background:rgba(255,255,255,.03); border:1px solid rgba(255,255,255,.08);
          border-radius:var(--radius); padding:12px;
          display:flex; flex-direction:column; gap:6px;
          cursor:pointer; transition:all .2s; text-align:left;
        }
        .style-btn:hover { background:rgba(255,255,255,.06); border-color:rgba(255,255,255,.15); }
        .style-btn.active {
          background:var(--admin-accent-dim); border-color:rgba(108,99,255,.5);
          box-shadow:0 0 12px rgba(108,99,255,.1);
        }
        .style-btn-name {
          font-family:'Cinzel',serif; font-size:10px; letter-spacing:.2em;
          color:var(--text-muted); text-transform:uppercase;
        }
        .style-btn.active .style-btn-name { color:var(--admin-accent); }
        .style-preview {
          color:rgba(255,255,255,.55); line-height:1.5;
          display:block; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;
        }

        /* ── image zone ── */
        .image-zone { display:flex; flex-direction:column; gap:10px; }
        .upload-btn {
          background:rgba(255,255,255,.02); border:1px dashed rgba(255,255,255,.12);
          border-radius:var(--radius); padding:24px;
          display:flex; flex-direction:column; align-items:center; gap:8px;
          cursor:pointer; transition:all .2s; width:100%; color:var(--text-muted);
          font-family:'Cormorant Garamond',serif; font-size:14px;
        }
        .upload-btn:hover { background:rgba(255,255,255,.05); border-color:rgba(108,99,255,.3); color:var(--text-dim); }
        .upload-icon { font-size:28px; }
        .upload-hint { font-size:11px; color:rgba(255,255,255,.2); }

        .image-preview-wrap { display:flex; flex-direction:column; gap:10px; }
        .image-preview {
          max-height:160px; max-width:100%; border-radius:var(--radius);
          object-fit:cover; border:1px solid rgba(255,255,255,.1);
        }
        .image-preview-actions { display:flex; gap:8px; }

        /* ── page cards ── */
        .page-card {
          background:rgba(255,255,255,.02);
          border:1px solid var(--admin-border);
          border-radius:var(--radius); overflow:hidden;
          transition:border-color .2s;
        }
        .page-card.open { border-color:rgba(108,99,255,.3); }
        .page-card-header {
          padding:14px 18px; display:flex; align-items:center;
          justify-content:space-between; cursor:pointer; gap:12px;
          transition:background .2s;
        }
        .page-card-header:hover { background:rgba(255,255,255,.03); }
        .page-card-left { display:flex; align-items:center; gap:14px; flex:1; min-width:0; }
        .page-card-num {
          font-family:'Cinzel',serif; font-size:12px;
          color:rgba(240,192,64,.4); min-width:22px; text-align:center;
        }
        .page-card-title {
          font-size:15px; color:var(--text-base);
          white-space:nowrap; overflow:hidden; text-overflow:ellipsis;
        }
        .page-card-chapter { font-size:11px; color:var(--text-muted); font-style:italic; }
        .page-card-badge {
          font-size:10px; padding:2px 8px; border-radius:20px;
          background:rgba(255,255,255,.06); color:var(--text-muted);
          white-space:nowrap; letter-spacing:.08em;
        }
        .page-card-badge.img { background:rgba(46,204,113,.1); color:rgba(46,204,113,.7); }
        .page-card-actions { display:flex; align-items:center; gap:6px; }
        .chevron { font-size:10px; color:var(--text-muted); margin-left:4px; }

        .page-card-body {
          padding:20px 18px; border-top:1px solid var(--admin-border);
          display:flex; flex-direction:column; gap:16px;
          background:rgba(0,0,0,.15);
        }

        /* ── buttons ── */
        .ad-btn {
          font-family:'Cinzel',serif; font-size:11px; letter-spacing:.15em;
          text-transform:uppercase; padding:9px 20px;
          border-radius:6px; border:none; cursor:pointer;
          transition:all .22s; display:inline-flex; align-items:center; gap:8px;
        }
        .ad-btn.primary {
          background:var(--admin-accent); color:#fff;
          box-shadow:0 4px 16px rgba(108,99,255,.3);
        }
        .ad-btn.primary:hover { background:#7c74ff; box-shadow:0 6px 20px rgba(108,99,255,.4); transform:translateY(-1px); }
        .ad-btn.secondary {
          background:rgba(255,255,255,.06); color:var(--text-dim);
          border:1px solid var(--admin-border);
        }
        .ad-btn.secondary:hover { background:rgba(255,255,255,.1); color:var(--text-base); }
        .ad-btn.danger { background:rgba(231,76,60,.12); color:rgba(231,76,60,.7); border:1px solid rgba(231,76,60,.2); }
        .ad-btn.danger:hover { background:rgba(231,76,60,.2); color:rgba(231,76,60,.9); }
        .ad-btn.gold {
          background:rgba(240,192,64,.1); color:rgba(240,192,64,.8);
          border:1px solid rgba(240,192,64,.25);
        }
        .ad-btn.gold:hover { background:rgba(240,192,64,.18); color:#f0c040; }
        .ad-btn.sm { padding:5px 13px; font-size:10px; }

        .icon-btn {
          width:28px; height:28px; border-radius:5px; border:none;
          background:rgba(255,255,255,.05); color:var(--text-muted);
          display:flex; align-items:center; justify-content:center;
          font-size:12px; cursor:pointer; transition:all .18s;
        }
        .icon-btn:hover:not(:disabled) { background:rgba(255,255,255,.12); color:var(--text-base); }
        .icon-btn:disabled { opacity:.2; cursor:not-allowed; }
        .icon-btn.danger:hover:not(:disabled) { background:rgba(231,76,60,.2); color:rgba(231,76,60,.9); }

        /* ── add page row ── */
        .add-row { display:flex; justify-content:center; padding:8px 0; }

        /* ── meta color pick ── */
        .color-row { display:flex; align-items:center; gap:12px; }
        .color-dot {
          width:32px; height:32px; border-radius:50%;
          border:2px solid rgba(255,255,255,.2);
        }

        /* ── reset section ── */
        .danger-zone {
          background:rgba(231,76,60,.04); border:1px solid rgba(231,76,60,.15);
          border-radius:var(--radius-lg); padding:20px 24px;
          display:flex; align-items:center; justify-content:space-between; gap:16px;
        }
        .danger-zone p { font-size:13px; color:rgba(255,255,255,.4); }
        .danger-zone strong { color:rgba(231,76,60,.6); display:block; font-family:'Cinzel',serif; font-size:12px; letter-spacing:.15em; margin-bottom:4px; }
      `}</style>

      <StarField count={50} />

      {/* top bar */}
      <div className="admin-bar">
        <div className="admin-bar-left">
          <span className="admin-logo">✦ Admin</span>
          <div className="admin-bar-sep" />
          <Link to="/" className="back-link">← Reader</Link>
        </div>
        <div className="admin-bar-right">
          {saved && <span className="save-badge">✓ Saved</span>}
          <button className="ad-btn primary" onClick={handleSave}>Save Changes</button>
        </div>
      </div>

      <div className="admin-layout">
        {/* tabs */}
        <div className="tab-bar">
          <button className={`tab-btn ${tab === 'pages' ? 'active' : ''}`} onClick={() => setTab('pages')}>Pages</button>
          <button className={`tab-btn ${tab === 'meta'  ? 'active' : ''}`} onClick={() => setTab('meta')}>Book Info</button>
        </div>

        {/* ── PAGES TAB ── */}
        {tab === 'pages' && (
          <>
            <div className="section-card">
              <div className="section-head">
                <span className="section-title">Pages ({book.pages.length})</span>
                <button className="ad-btn gold" onClick={() => { addPage(); }}>＋ Add Page</button>
              </div>
              <div className="section-body">
                {book.pages.length === 0 && (
                  <p style={{ textAlign:'center', color:'var(--text-muted)', padding:'30px 0', fontStyle:'italic' }}>
                    No pages yet. Click "Add Page" to begin.
                  </p>
                )}
                {book.pages.map((page, i) => (
                  <PageEditor
                    key={page.id}
                    page={page}
                    index={i}
                    total={book.pages.length}
                    onUpdate={(updates) => updatePage(page.id, updates)}
                    onDelete={() => deletePage(page.id)}
                    onMoveUp={() => movePage(page.id, -1)}
                    onMoveDown={() => movePage(page.id, 1)}
                  />
                ))}
              </div>
            </div>

            <div className="add-row">
              <button className="ad-btn secondary" onClick={() => addPage()}>＋ Add Another Page</button>
            </div>
          </>
        )}

        {/* ── META TAB ── */}
        {tab === 'meta' && (
          <>
            <div className="section-card">
              <div className="section-head">
                <span className="section-title">Book Information</span>
              </div>
              <div className="section-body">
                <Field label="Book Title">
                  <Input value={book.title} onChange={v => updateBook({ title: v })} placeholder="The Cosmos Within" />
                </Field>
                <Field label="Subtitle" hint="Optional tagline shown below the title on the cover">
                  <Input value={book.subtitle || ''} onChange={v => updateBook({ subtitle: v })} placeholder="A journey through space and mind" />
                </Field>
                <Field label="Author Name">
                  <Input value={book.author} onChange={v => updateBook({ author: v })} placeholder="Eleanor Voss" />
                </Field>
                <Field label="Cover Accent Color" hint="The dominant colour of the book cover gradient">
                  <div className="color-row">
                    <div className="color-dot" style={{ background: book.coverColor || '#302b63' }} />
                    <input
                      type="color"
                      className="ad-input"
                      value={book.coverColor || '#302b63'}
                      onChange={e => updateBook({ coverColor: e.target.value })}
                      style={{ width: 80, height: 40, padding: 4, cursor: 'pointer' }}
                    />
                    <span style={{ color:'var(--text-muted)', fontSize:13, fontStyle:'italic' }}>
                      Pick any colour — the cover uses it as the mid-stop of the gradient
                    </span>
                  </div>
                </Field>
              </div>
            </div>

            <div className="danger-zone">
              <div>
                <strong>⚠ Reset Book</strong>
                <p>Discard all changes and restore the original demo content. This cannot be undone.</p>
              </div>
              <button className="ad-btn danger" onClick={() => { if (window.confirm('Reset to default content?')) resetBook(); }}>
                Reset to Demo
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
